<template><div class="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50/30 p-6"><div class="mb-8"><div class="flex items-center justify-between"><div><h1 class="text-3xl font-bold bg-gradient-to-r from-slate-800 to-blue-600 bg-clip-text text-transparent mb-2">📍 Location Management</h1><p class="text-slate-600 font-light">Manage service locations</p></div><button @click="refreshData" class="p-2 hover:bg-white/50 rounded-xl transition-all duration-300"><ArrowPathIcon class="w-6 h-6 text-slate-600" /></button></div></div><div v-if="error" class="bg-rose-50 border border-rose-200 rounded-2xl p-6 mb-6"><div class="flex items-center justify-between"><div class="flex items-center space-x-3"><ExclamationTriangleIcon class="w-6 h-6 text-rose-600" /><div><h3 class="text-rose-800 font-semibold">Failed to load location data</h3><p class="text-rose-600 text-sm">{{ error }}</p></div></div><button @click="fetchLocations" class="px-4 py-2 bg-rose-600 text-white rounded-lg hover:bg-rose-700">Retry</button></div></div><div v-if="loading && !error" class="flex items-center justify-center py-20"><div class="text-center"><div class="relative"><div class="w-16 h-16 border-4 border-blue-200 rounded-full"></div><div class="w-16 h-16 border-4 border-transparent border-t-blue-500 rounded-full animate-spin absolute top-0 left-0"></div></div><p class="mt-4 text-slate-500 font-light">Loading locations...</p></div></div><div v-else-if="!loading" class="space-y-8"><div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6"><ModernMetricCard title="Total Locations" :value="stats.total_locations" icon="📍" color="blue" :formatted="true" /><ModernMetricCard title="Active" :value="stats.active_locations" icon="✅" color="emerald" :formatted="true" /><ModernMetricCard title="Regions" :value="stats.by_region?.length || 0" icon="🗺️" color="purple" :formatted="true" /><ModernMetricCard title="Clients" :value="stats.top_locations?.[0]?.client_count || 0" icon="👥" color="cyan" :formatted="true" /></div><SearchBar v-model="searchTerm" placeholder="Search locations..." :filters="filters" @filter-change="handleFilterChange" @clear="clearFilters" @add="openCreateModal" /><DataTable title="Location Records" :data="filteredLocations" :columns="columns" :actions="['edit', 'delete']" @edit="openEditModal" @delete="openDeleteModal"><template #cell-is_active="{ value }"><span :class="value ? 'bg-emerald-100 text-emerald-800' : 'bg-slate-100 text-slate-800'" class="px-2 py-1 text-xs font-medium rounded-full">{{ value ? 'Active' : 'Inactive' }}</span></template></DataTable></div><FormModal :show="showFormModal" title="Location" :fields="formFields" :initial-data="selectedLocation" :loading="saveLoading" @close="closeFormModal" @submit="saveLocation" /><ConfirmDialog :show="showDeleteModal" title="Delete Location" :message="`Delete location <strong>${locationToDelete?.name}</strong>?`" type="danger" :loading="deleteLoading" @confirm="confirmDelete" @cancel="closeDeleteModal" /></div></template><script>import { ref, computed, onMounted } from 'vue';import { useApi } from '../composables/useApi';import ModernMetricCard from '../components/MetricCard.vue';import SearchBar from '../components/SearchBar.vue';import DataTable from '../components/DataTable.vue';import FormModal from '../components/FormModal.vue';import ConfirmDialog from '../components/ConfirmDialog.vue';import { ArrowPathIcon, ExclamationTriangleIcon } from '@heroicons/vue/24/outline';export default {name:'Locations',components:{ModernMetricCard,SearchBar,DataTable,FormModal,ConfirmDialog,ArrowPathIcon,ExclamationTriangleIcon},setup(){const {loading,error,makeRequest}=useApi();const locations=ref([]);const stats=ref({});const searchTerm=ref('');const activeFilters=ref({});const showFormModal=ref(false);const showDeleteModal=ref(false);const selectedLocation=ref(null);const locationToDelete=ref(null);const saveLoading=ref(false);const deleteLoading=ref(false);const columns=[{key:'id',label:'ID',sortable:true},{key:'name',label:'Name',sortable:true},{key:'address',label:'Address',sortable:true},{key:'city',label:'City',sortable:true},{key:'region',label:'Region',sortable:true},{key:'is_active',label:'Status',sortable:true},{key:'client_count',label:'Clients',sortable:true}];const filters=[{key:'is_active',label:'Status',options:[{value:'true',label:'Active'},{value:'false',label:'Inactive'}]}];const formFields=[{key:'name',label:'Location Name',type:'text',required:true},{key:'address',label:'Address',type:'text',required:true},{key:'city',label:'City',type:'text',required:true},{key:'region',label:'Region',type:'text',required:true},{key:'is_active',label:'Active',type:'checkbox',checkboxLabel:'Location is active'}];const filteredLocations=computed(()=>{let result=locations.value;if(searchTerm.value){const term=searchTerm.value.toLowerCase();result=result.filter(l=>l.name?.toLowerCase().includes(term)||l.city?.toLowerCase().includes(term)||l.region?.toLowerCase().includes(term))}Object.keys(activeFilters.value).forEach(key=>{const value=activeFilters.value[key];if(value)result=result.filter(l=>l[key]===(value==='true'))});return result});const fetchLocations=async()=>{try{const data=await makeRequest('get','locations/');locations.value=data.results||data}catch(err){console.error('Error:',err)}};const fetchStats=async()=>{try{stats.value=await makeRequest('get','locations/stats/')}catch(err){console.error('Error:',err)}};const refreshData=()=>Promise.all([fetchLocations(),fetchStats()]);const handleFilterChange=({all})=>{activeFilters.value=all};const clearFilters=()=>{searchTerm.value='';activeFilters.value={}};const openCreateModal=()=>{selectedLocation.value=null;showFormModal.value=true};const openEditModal=(location)=>{selectedLocation.value={...location};showFormModal.value=true};const closeFormModal=()=>{showFormModal.value=false;selectedLocation.value=null};const saveLocation=async(data)=>{saveLoading.value=true;try{const endpoint=data.id?`locations/${data.id}/`:'locations/';const method=data.id?'put':'post';await makeRequest(method,endpoint,data);await refreshData();closeFormModal()}catch(err){alert('Error: '+(err.response?.data?.error||err.message))}finally{saveLoading.value=false}};const openDeleteModal=(location)=>{locationToDelete.value=location;showDeleteModal.value=true};const closeDeleteModal=()=>{showDeleteModal.value=false;locationToDelete.value=null};const confirmDelete=async()=>{deleteLoading.value=true;try{await makeRequest('delete',`locations/${locationToDelete.value.id}/`);await refreshData();closeDeleteModal()}catch(err){alert('Error: '+(err.response?.data?.error||err.message))}finally{deleteLoading.value=false}};onMounted(refreshData);return{loading,error,locations,stats,searchTerm,showFormModal,showDeleteModal,selectedLocation,locationToDelete,saveLoading,deleteLoading,columns,filters,formFields,filteredLocations,fetchLocations,refreshData,handleFilterChange,clearFilters,openCreateModal,openEditModal,closeFormModal,saveLocation,openDeleteModal,closeDeleteModal,confirmDelete}}}</script>
